mapper.insert:
INSERT INTO item_usage_log (
logno, memberno, item_type, used_at
) VALUES (
item_usage_log_seq.NEXTVAL, #{memberno}, #{item_type}, SYSDATE
)

mapper.select:
SELECT COUNT(*)
FROM item_usage_log
WHERE memberno = #{memberno}
AND item_type = #{item_type}
AND TO_CHAR(used_at, 'YYYYMMDD') = TO_CHAR(SYSDATE, 'YYYYMMDD')
